/* {{pp-template}} */
.templatequote {
	overflow: hidden;
	margin: 1em 0;
	padding: 0 32px;
}

.templatequotecite {
    line-height: 1.5em;
    /* @noflip */
    text-align: left;
    margin-top: 0;
}

@media (min-width: 500px) {
	.templatequotecite {
	    /* @noflip */
	    padding-left: 1.6em;
	}
}

/* Styling for Template:Quote */
.templatequote {
     margin-top: 0;
}
.templatequote .templatequotecite {
    line-height: 1.5em;
    /* @noflip */
    text-align: left;
    /* @noflip */
    padding-left: 1.6em;
    margin-top: 0;
}

